scwin.f_AddItem = function () {
  if (ds_unionOrgnizationTreeView.getModifiedJSON().length > 0) {
    $c.win.alert($p, '변경 사항이 존재합니다.');
    return;
  }
  scwin.isValid = true;
  $c.gus.cfEnableObjects($p, [ed_lunionOrgCd, ed_lunionOrgCd01]);
  rd_lunionCls01.setDisabled(true);

  //var ds_unionOrgnizationTreeView.insertRow();
  //rd_lunionCls01.Enable = "false";
  //console.log('scwin.f_AddItem~~~'+ds_unionOrgnizationTreeView.getRowPosition());

  var row = 0;
  var newRow = 0;
  if (ds_unionOrgnizationTreeView.getRowCount() > 0) {
    row = ds_unionOrgnizationTreeView.getRowPosition();
    newRow = row + 1;
  }
  var nlvl = parseInt(ds_unionOrgnizationTreeView.getCellData(row, 'lvl'));
  if (nlvl >= 3) {
    return;
  }
  console.log('nlvl~~' + nlvl);
  ds_unionOrgnizationTreeView.insertRow(newRow);
  if (row == 0) {
    ds_unionOrgnizationTreeView.setCellData(newRow, 'lvl', nlvl);
    ds_unionOrgnizationTreeView.setCellData(newRow, 'testLvl', nlvl + 1);
  } else {
    ds_unionOrgnizationTreeView.setCellData(newRow, 'lvl', nlvl + 1);
    ds_unionOrgnizationTreeView.setCellData(newRow, 'testLvl', nlvl + 2);
  }

  //ds_unionOrgnizationTreeView.setCellData(newRow, 'lvl', nlvl+1);

  ds_unionOrgnizationTreeView.setCellData(newRow, 'lunionOrgCd', '');
  ds_unionOrgnizationTreeView.setCellData(newRow, 'lunionOrgNm', '신규 추가 등록');
  ds_unionOrgnizationTreeView.setRowPosition(newRow);
  //tv_unionOrgnizationTree.findNodeByIndex(newRow);

  if (ds_unionOrgnizationTreeView.getCellData(newRow, 'lvl') == 1) {
    ds_level1.insertRow(0);
    $c.gus.cfDisableObjects($p, [tbl_menuInfo01]);
    $c.gus.cfEnableObjects($p, [tbl_menuInfo]);
  } else if (ds_unionOrgnizationTreeView.getCellData(newRow, 'lvl') == 2 || ds_unionOrgnizationTreeView.getCellData(newRow, 'lvl') == 3) {
    //if(tv_unionOrgnizationTree.ItemLevel == 3 ) ds_Inspection.NameValue( 1,  "lunionOrgCd" ) = em_lunionOrgCd.Text; 
    //if(tv_unionOrgnizationTree.ItemLevel == 2 ) ds_Inspection.NameValue( 1,  "lunionOrgCd" ) = ds_unionOrgnizationTree.NameValue(ds_unionOrgnizationTree.RowPosition-1 , "lunionOrgCd" ); 

    if (ds_unionOrgnizationTreeView.getCellData(newRow, 'lvl') == 3) {
      ds_Inspection.set("lunionOrgCd", ds_level1.getCellData(0, "lunionOrgCd"));
    } else if (ds_unionOrgnizationTreeView.getCellData(newRow, 'lvl') == 2) {
      ds_Inspection.set("lunionOrgCd", ed_lunionOrgCd.getValue());
    }
    ds_Inspection.set("lvl", 1);
    scwin.f_detailRetrieve();

    /*  f_detailRetrieve() 실행 후 콜백에서처리. scwin.f_AddItemAfter 
        ds_level23.insertRow(0);
        $c.gus.cfDisableObjects([tbl_menuInfo]);
        $c.gus.cfEnableObjects([tbl_menuInfo01]);
        rd_lunionCls01.setDisabled(true);
        ds_level23.setCellData(0, "lvl", ds_unionOrgnizationTreeView.getCellData(newRow, "lvl"));
    
        //분회 / 반 구분값 셋팅 
        if(ds_level23.getCellData(0, "lvl") == '2'){
            ds_level23.setCellData(0, "lunionCls", "01");
        }else if(ds_level23.getCellData(0, "lvl") == '3'){
            ds_level23.setCellData(0, "lunionCls", "02");
        }
    
        //항구코드 셋팅
        ds_level23.setCellData(0,"portCd", ds_level1.getCellData(0, "portCd"));
        ds_level23.setCellData(0,"portNm", ds_level1.getCellData(0, "portNm"));
    
        //물류점코드셋팅
        ds_level23.setCellData(0,"lobranCd", ds_level1.getCellData(0, "lobranCd"));
        ds_level23.setCellData(0,"lobranNm", ds_level1.getCellData(0, "lobranNm"));
     //debugger;
        //상위코드셋팅
        if(ds_level23.getCellData(0, "lvl") == '2'){
            ds_level23.setCellData(0,"upperOrgCd", ds_level1.getCellData(0 , "lunionOrgCd" ));
        }else if(ds_level23.getCellData(0, "lvl") == '3'){
            ds_level23.setCellData(0,"upperOrgCd", ds_unionOrgnizationTreeView.getCellData(row , "lunionOrgCd" ));
        }
    */
  }

  //scwin.isValid = true;
};
scwin.f_AddItemAfter = function () {
  console.log('scwin.f_AddItemAfter~~');
  var row = ds_unionOrgnizationTreeView.getRowPosition() - 1;
  var newRow = ds_unionOrgnizationTreeView.getRowPosition();
  if (ds_level23.getRowCount() == 0) {
    ds_level23.insertRow(0);
  }
  ds_level23.setRowPosition(0);

  //console.log('row~~'+row);
  //console.log('newRow~~'+newRow);
  //console.log('ds_level23~~'+ds_level23.getRowPosition());

  $c.gus.cfDisableObjects($p, [tbl_menuInfo]);
  $c.gus.cfEnableObjects($p, [tbl_menuInfo01]);
  rd_lunionCls01.setDisabled(true);
  ds_level23.setCellData(0, "lvl", ds_unionOrgnizationTreeView.getCellData(newRow, "lvl"));

  //분회 / 반 구분값 셋팅 
  if (ds_level23.getCellData(0, "lvl") == '2') {
    //console.log('111111111111111~~');
    ds_level23.setCellData(0, "lunionCls", "01");
  } else if (ds_level23.getCellData(0, "lvl") == '3') {
    //console.log('222222222222222~~');
    ds_level23.setCellData(0, "lunionCls", "02");
  }

  //항구코드 셋팅
  ds_level23.setCellData(0, "portCd", ds_level1.getCellData(0, "portCd"));
  ds_level23.setCellData(0, "portNm", ds_level1.getCellData(0, "portNm"));

  //물류점코드셋팅
  ds_level23.setCellData(0, "lobranCd", ds_level1.getCellData(0, "lobranCd"));
  ds_level23.setCellData(0, "lobranNm", ds_level1.getCellData(0, "lobranNm"));
  //debugger;
  //상위코드셋팅
  if (ds_level23.getCellData(0, "lvl") == '2') {
    ds_level23.setCellData(0, "upperOrgCd", ds_level1.getCellData(0, "lunionOrgCd"));
  } else if (ds_level23.getCellData(0, "lvl") == '3') {
    ds_level23.setCellData(0, "upperOrgCd", ds_unionOrgnizationTreeView.getCellData(row, "lunionOrgCd"));
  }
};
//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) return;

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);
  scwin.f_openTextPopUp(disGubun);
};

