scwin.sbm_selectRetrieve_submitdone = function (e) {
  //console.log('scwin.sbm_selectRetrieve_submitdone222 ~~');
  if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

  var rowcnt = ds_unionOrgnizationTree.getRowCount();
  if (rowcnt == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003, [""]); // alert("조회된 데이터가 없습니다.");
  } else {
    /*
            for(var i=0;i<ds_unionOrgnizationTree.getRowCount();i++){
                //if(i>0 && ds_unionOrgnizationTree.getCellData(i, "upperOrgCd") == ""){
                //    ds_unionOrgnizationTree.setCellData(i, "upperOrgCd", "T");
                //}
    
                var lvl = parseInt(ds_unionOrgnizationTree.getCellData(i, "lvl"))+1;
                ds_unionOrgnizationTree.setCellData(i, "lvl", lvl);
            }
    */

    ds_unionOrgnizationTree.insertRow(0);
    ds_unionOrgnizationTree.setCellData(0, "lunionOrgCd", "");
    ds_unionOrgnizationTree.setCellData(0, "lunionOrgNm", "노조조직");
    ds_unionOrgnizationTree.setCellData(0, "lvl", 1);
    ds_unionOrgnizationTree.setCellData(0, "testLvl", 1);
    for (var i = 0; i < ds_unionOrgnizationTree.getRowCount(); i++) {
      if (i != 0) {
        var lvl = parseInt(ds_unionOrgnizationTree.getCellData(i, "lvl")) + 1;
        ds_unionOrgnizationTree.setCellData(i, "testLvl", lvl);
      }
    }

    //ds_unionOrgnizationTreeView.reform();
    //tv_unionOrgnizationTree.focus();

    //tv_unionOrgnizationTree.Index = hid_tvIndex.getValue();
    //tv_unionOrgnizationTree.Expand(hid_tvIndex.getValue());
    //tv_unionOrgnizationTree.Index = 2;

    //$c.gus.cfCopyDataSet(ds_unionOrgnizationTree, ds_unionOrgnizationTreeView, "copyHeader=yes"); 데이터셋 카피
    ds_unionOrgnizationTreeView.setJSON(ds_unionOrgnizationTree.getAllJSON());
    tv_unionOrgnizationTree.findNodeByIndex(scwin.hid_tvIndex, true);
    if (ds_unionOrgnizationTreeView.getRowCount() > 1) {
      ds_unionOrgnizationTreeView.setRowPosition(1);
      scwin.tv_unionOrgnizationTree_onclick();
    }
    tv_unionOrgnizationTree.focus();
  }
};
scwin.sbm_Retrieve_submitdone = function (e) {
  if (ds_level1.getRowCount() > 0) ds_level1.setRowPosition(0);
  if (ds_level23.getRowCount() > 0) ds_level23.setRowPosition(0);
  if (scwin.isValid == true) {
    scwin.f_AddItemAfter();
  }
};
scwin.sbm_lunionCls_submitdone = function (e) {
  var row = ds_lunionCls.getRowCount();
  for (var i = 0; i < row; i++) {
    rd_lunionCls.addItem(ds_lunionCls.getCellData(i, 'code'), ds_lunionCls.getCellData(i, 'name'), i);
  }
  if (row > 0) rd_lunionCls.setSelectedIndex(0);
  rd_lunionCls.setMandatory(true);
};
scwin.sbm_save_submitdone = async function (e) {
  await $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
  //ds_Inspection.UserStatus(1) = "1"; //임의로 dataset status를 insert 로 수정 한다.
  $c.gus.cfEnableObjects($p, [tbl_menuInfo]);
  $c.gus.cfEnableObjects($p, [tbl_menuInfo01]);
  $c.gus.cfDisableObjects($p, [ed_lunionOrgCd, ed_lunionOrgCd01]);
  rd_lunionCls01.setDisabled(true);
  //rd_lunionCls01.Enable = "false";

  scwin.isValid = false;
  scwin.f_Retrieve();
  ds_Inspection.set("lunionOrgCd", ds_unionOrgnizationTreeView.getCellData(2, "lunionOrgCd"));
  ds_Inspection.set("lvl", 1);
  scwin.f_detailRetrieve();
};
